3_real_world_example.code:
// Normal function
function getSyncName() { 
  return 'Alice'; 
}
console.log(getSyncName()); // 'Alice'

// Async function
async function getAsyncName() { 
  return 'Alice'; // Automatically wrapped in a Promise!
}
console.log(getAsyncName()); // Promise { <fulfilled>: 'Alice' }

// Extracting the value
getAsyncName().then(name => console.log(name)); // 'Alice'

6_edge_case.code:
async function doublePromise() {
  return Promise.resolve(42); // Not double-wrapped
}
doublePromise().then(val => console.log(val)); // 42
